P loadText        B
D loadText        PI
D   loadType                     3A   value
D*----------------------------------------------------------------
  // Subfile l�schen
  ZLT = 0;
  *IN90 = *Off;
  *IN99 = *On;
  Write HS1212CT;
  // Subfile f�llen
  *IN90 = *On;
  *IN99 = *Off;
  If loadType = 'GPT';
     loadtextGPT(0);
  EndIf;
  If loadType = 'GPS';
     loadtextGPS(0);
  EndIf;
  If ZLT = 0;
     TEXT = G7312A;
     ZLT += 1;
     Write HS1212ST;
     TEXT = G7313A;
     ZLT += 1;
     Write HS1212ST;
     TEXT = G7332A;
     ZLT += 1;
     Write HS1212ST;
     TEXT = G7333A;
     ZLT += 1;
     Write HS1212ST;
     loadtextGPT(ZLT);
  EndIf;
  exec sql close ct;
  DOW ZLT < 99;
     TEXT = *Blanks;
     ZLT += 1;
     Write HS1212ST;
  EndDo;
  loadTextFromSfl();
P                 E
